import Foundation

enum LogLevel {
    case debug
    case info
    case warning
    case error
}

class AnalyticsLogger {
    static let shared = AnalyticsLogger()
    
    private init() {}
    
    var logLevel: LogLevel = .info
    
    func log(_ message: String, level: LogLevel = .info) {
        guard shouldLog(level) else { return }
        NSLog(message)
    }
    
    private func shouldLog(_ level: LogLevel) -> Bool {
        switch (self.logLevel, level) {
        case (.debug, _):
            return true
        case (.info, .info), (.info, .warning), (.info, .error):
            return true
        case (.warning, .warning), (.warning, .error):
            return true
        case (.error, .error):
            return true
        default:
            return false
        }
    }
    
    func logUserInteraction(userId: String, action: String) {
        log("User Interaction - UserID: \(userId), Action: \(action)", level: .info)
    }
    
    func logAuthenticationFlow(userId: String, success: Bool) {
        log("Authentication Flow - UserID: \(userId), Success: \(success)", level: .info)
    }
    
    func logAPICall(endpoint: String, requestPayload: [String: Any]?) {
        let sanitizedPayload = requestPayload?.reduce(into: [String: Any]()) { result, pair in
            if pair.key.lowercased() != "token" && pair.key.lowercased() != "password" {
                result[pair.key] = pair.value
            }
        }
        log("API Call - Endpoint: \(endpoint), Request: \(String(describing: sanitizedPayload))", level: .debug)
    }
    
    func logAPIResponse(endpoint: String, responsePayload: [String: Any]?) {
        let sanitizedPayload = responsePayload?.reduce(into: [String: Any]()) { result, pair in
            if pair.key.lowercased() != "token" && pair.key.lowercased() != "password" {
                result[pair.key] = pair.value
            }
        }
        log("API Response - Endpoint: \(endpoint), Response: \(String(describing: sanitizedPayload))", level: .debug)
    }
    
    func logUserDataChange(userId: String, changes: [String: Any]) {
        log("User Data Change - UserID: \(userId), Changes: \(String(describing: changes))", level: .info)
    }
    
    func logError(_ error: Error) {
        log("Error Occurred: \(error.localizedDescription)", level: .error)
    }
}